mapper.select:
SELECT COUNT(1)
FROM message
WHERE conversation_id = #{cid}

SELECT COUNT(1) FROM message m
AND m.conversation_id = #{conversationId}
AND m.content LIKE CONCAT('%', #{keyword}, '%')

SELECT m.id, m.conversation_id AS conversationId, m.user_id AS userId, m.type, m.content AS content, m.emotion, m.confidence, m.is_read AS isRead, m.create_time AS createTime, m.update_time AS updateTime FROM message m
AND m.conversation_id = #{conversationId}
AND m.content LIKE CONCAT('%', #{keyword}, '%')
ORDER BY m.id DESC LIMIT #{size} OFFSET #{offset}
